 19→public fun ASTNode.nextLeaf(
 20→    includeEmpty: Boolean = false,
 21→    skipSubtree: Boolean = false,
 22→): ASTNode? {
 23→    var n = if (skipSubtree) this.lastChildLeafOrSelf().nextLeafAny() else this.nextLeafAny()
 24→    if (!includeEmpty) {
 25→        while (n != null && n.textLength == 0) {
 26→            n = n.nextLeafAny()
 27→        }
 28→    }
 29→    return n
 30→}
 31→
 32→public fun ASTNode.nextLeaf(p: (ASTNode) -> Boolean): ASTNode? {
 33→    var n = this.nextLeafAny()
 34→    while (n != null && !p(n)) {
 35→        n = n.nextLeafAny()
 36→    }
 37→    return n
 38→}
 39→
 40→private fun ASTNode.nextLeafAny(): ASTNode? {
 41→    var n = this
 42→    if (n.firstChildNode != null) {
 43→        do {
 44→            n = n.firstChildNode
 45→        } while (n.firstChildNode != null)
 46→        return n
 47→    }
 48→    return n.nextLeafStrict()
 49→}
 50→
 51→private fun ASTNode.nextLeafStrict(): ASTNode? {
 52→    val nextSibling: ASTNode? = treeNext
 53→    if (nextSibling != null) {
 54→        return nextSibling.firstChildLeafOrSelf()
 55→    }
 56→    return treeParent?.nextLeafStrict()
 57→}
