 59→public fun ASTNode.firstChildLeafOrSelf(): ASTNode {
 60→    var n = this
 61→    if (n.firstChildNode != null) {
 62→        do {
 63→            n = n.firstChildNode
 64→        } while (n.firstChildNode != null)
 65→        return n
 66→    }
 67→    return n
 68→}
