    private val wrappingRuleAssertThat = assertThatRule { com.pinterest.ktlint.ruleset.standard.rules.WrappingRule() }

    @Test
    fun `Issue 673 - annotations inside TypeArgumentList should not be wrapped`() {
        val code =
            """
            annotation class Valid
            annotation class NotNull
            data class FooDto(val value: String)

            data class FooRequestDto(
                val data: List<@Valid @NotNull FooDto>,
            )
            """.trimIndent()

        wrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Issue 673 - single annotation inside TypeArgumentList should not add comma`() {
        val code =
            """
            annotation class Valid
            data class FooDto(val value: String)

            data class FooRequestDto(
                val data: List<@Valid FooDto>,
            )
            """.trimIndent()

        wrappingRuleAssertThat(code).hasNoLintViolations()
    }
