367→/**
368→ * Creates a sequences of leaves including the [ASTNode] in case it is a [LeafElement] itself. By default, the leaves are traversed in
369→ * forward order. Setting [forward] to `false` changes this to traversal in backward direction.
370→ */
371→public fun ASTNode.leavesIncludingSelf(forward: Boolean = true): Sequence<ASTNode> {
372→    val sequence =
373→        if (isLeaf()) {
374→            sequenceOf(this)
375→        } else {
376→            emptySequence()
377→        }
378→    return sequence.plus(leaves(forward))
379→}
